mapper.select:
select from share sh left join student s on sh.student_id = s.id
and sh.title like concat('%', #{title}, '%')
and sh.student_id = #{studentId}
and sh.status = #{status}
order by sh.create_time desc

mapper.update:
update share
title = #{title}, content = #{content}, status = #{status},
where id = #{id}
